{
    "query": "query { encounters { id resourceType status class_value { system code display } subject { reference display } period { start end } } }"
}

{
    "query": "query($status: String) { encounters(status: $status) { id resourceType status class_value { system code display } subject { reference display } period { start end } } }",
    "variables": {
        "status": "in-progress"
    }
}

{
    "query": "query($id: String!) { encounter(id: $id) { id resourceType status class_value { system code display } type { coding { system code display } text } subject { reference display } period { start end } } }",
    "variables": {
        "id": "{{encounter_id}}"
    }
}

{
    "query": "query($patientId: String!, $status: String) { patientEncounters(patientId: $patientId, status: $status) { id resourceType status class_value { system code display } subject { reference display } period { start end } } }",
    "variables": {
        "patientId": "123",
        "status": "in-progress"
    }
}

